import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Grid,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Chip,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Alert,
  Tabs,
  Tab,
  Switch,
  FormControlLabel,
  Tooltip,
  Badge
} from '@mui/material';
import {
  Visibility,
  Block,
  CheckCircle,
  Cancel,
  SupervisorAccount,
  TrendingUp,
  TrendingDown,
  Close,
  Search,
  Refresh,
  Group,
  Assessment,
  Security
} from '@mui/icons-material';
import { toast } from 'react-toastify';

const AdminDashboard = () => {
  const [currentTab, setCurrentTab] = useState(0);
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userDetailsOpen, setUserDetailsOpen] = useState(false);
  const [symbolTrades, setSymbolTrades] = useState([]);
  const [openPositions, setOpenPositions] = useState([]);
  const [adminStats, setAdminStats] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [selectedPositions, setSelectedPositions] = useState([]);
  const [closePositionDialog, setClosePositionDialog] = useState(false);

  useEffect(() => {
    loadInitialData();
  }, []);

  const loadInitialData = async () => {
    setLoading(true);
    try {
      await Promise.all([
        loadUsers(),
        loadSymbolTrades(),
        loadOpenPositions(),
        loadAdminStats()
      ]);
    } catch (error) {
      console.error('Erro ao carregar dados:', error);
      toast.error('Erro ao carregar dados administrativos');
    } finally {
      setLoading(false);
    }
  };

  const loadUsers = async () => {
    try {
      const response = await fetch('/api/admin/users', {
        credentials: 'include'
      });
      const data = await response.json();
      
      if (response.ok) {
        setUsers(data.users || []);
      } else {
        throw new Error(data.message || 'Erro ao carregar usuários');
      }
    } catch (error) {
      console.error('Erro ao carregar usuários:', error);
    }
  };

  const loadUserDetails = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}`, {
        credentials: 'include'
      });
      const data = await response.json();
      
      if (response.ok) {
        setSelectedUser(data);
        setUserDetailsOpen(true);
      } else {
        throw new Error(data.message || 'Erro ao carregar detalhes do usuário');
      }
    } catch (error) {
      console.error('Erro ao carregar detalhes:', error);
      toast.error('Erro ao carregar detalhes do usuário');
    }
  };

  const loadSymbolTrades = async () => {
    try {
      const response = await fetch('/api/admin/trades/by-symbol', {
        credentials: 'include'
      });
      const data = await response.json();
      
      if (response.ok) {
        setSymbolTrades(data.symbols || []);
      } else {
        throw new Error(data.message || 'Erro ao carregar trades por símbolo');
      }
    } catch (error) {
      console.error('Erro ao carregar trades por símbolo:', error);
    }
  };

  const loadOpenPositions = async () => {
    try {
      const response = await fetch('/api/admin/positions/open', {
        credentials: 'include'
      });
      const data = await response.json();
      
      if (response.ok) {
        setOpenPositions(data.open_positions || []);
      } else {
        throw new Error(data.message || 'Erro ao carregar posições abertas');
      }
    } catch (error) {
      console.error('Erro ao carregar posições abertas:', error);
    }
  };

  const loadAdminStats = async () => {
    try {
      const response = await fetch('/api/admin/dashboard/stats', {
        credentials: 'include'
      });
      const data = await response.json();
      
      if (response.ok) {
        setAdminStats(data);
      } else {
        throw new Error(data.message || 'Erro ao carregar estatísticas');
      }
    } catch (error) {
      console.error('Erro ao carregar estatísticas:', error);
    }
  };

  const toggleUserStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-status`, {
        method: 'POST',
        credentials: 'include'
      });
      const data = await response.json();
      
      if (response.ok) {
        toast.success(data.message);
        loadUsers(); // Recarregar lista
      } else {
        throw new Error(data.message || 'Erro ao alterar status do usuário');
      }
    } catch (error) {
      console.error('Erro ao alterar status:', error);
      toast.error('Erro ao alterar status do usuário');
    }
  };

  const closeSelectedPositions = async () => {
    try {
      const response = await fetch('/api/admin/positions/close', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        credentials: 'include',
        body: JSON.stringify({
          action_type: 'single',
          trade_ids: selectedPositions,
          reason: 'Fechamento administrativo via painel'
        })
      });
      const data = await response.json();
      
      if (response.ok) {
        toast.success(data.message);
        setSelectedPositions([]);
        setClosePositionDialog(false);
        loadOpenPositions(); // Recarregar posições
      } else {
        throw new Error(data.message || 'Erro ao fechar posições');
      }
    } catch (error) {
      console.error('Erro ao fechar posições:', error);
      toast.error('Erro ao fechar posições');
    }
  };

  const closeAllSymbolPositions = async (symbol) => {
    try {
      const response = await fetch('/api/admin/positions/close', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        credentials: 'include',
        body: JSON.stringify({
          action_type: 'all_symbol',
          symbol: symbol,
          reason: `Fechamento administrativo de todas as posições ${symbol}`
        })
      });
      const data = await response.json();
      
      if (response.ok) {
        toast.success(data.message);
        loadOpenPositions(); // Recarregar posições
      } else {
        throw new Error(data.message || 'Erro ao fechar posições');
      }
    } catch (error) {
      console.error('Erro ao fechar posições:', error);
      toast.error('Erro ao fechar posições do símbolo');
    }
  };

  const filteredUsers = users.filter(user => {
    const matchesSearch = user.full_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.email.toLowerCase().includes(searchTerm.toLowerCase());
    
    if (statusFilter === 'active') return matchesSearch && user.is_active;
    if (statusFilter === 'inactive') return matchesSearch && !user.is_active;
    return matchesSearch;
  });

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'USD'
    }).format(value || 0);
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleString('pt-BR');
  };

  // Renderizar painel de estatísticas
  const renderStatsPanel = () => (
    <Grid container spacing={3} sx={{ mb: 3 }}>
      <Grid item xs={12} md={3}>
        <Card>
          <CardContent>
            <Box display="flex" alignItems="center">
              <Group color="primary" sx={{ mr: 2 }} />
              <Box>
                <Typography variant="h6" component="div">
                  {adminStats?.general_stats?.total_users || 0}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Total de Usuários
                </Typography>
              </Box>
            </Box>
          </CardContent>
        </Card>
      </Grid>
      
      <Grid item xs={12} md={3}>
        <Card>
          <CardContent>
            <Box display="flex" alignItems="center">
              <CheckCircle color="success" sx={{ mr: 2 }} />
              <Box>
                <Typography variant="h6" component="div">
                  {adminStats?.general_stats?.active_users || 0}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Usuários Ativos
                </Typography>
              </Box>
            </Box>
          </CardContent>
        </Card>
      </Grid>
      
      <Grid item xs={12} md={3}>
        <Card>
          <CardContent>
            <Box display="flex" alignItems="center">
              <Assessment color="info" sx={{ mr: 2 }} />
              <Box>
                <Typography variant="h6" component="div">
                  {adminStats?.general_stats?.total_trades || 0}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Total de Trades
                </Typography>
              </Box>
            </Box>
          </CardContent>
        </Card>
      </Grid>
      
      <Grid item xs={12} md={3}>
        <Card>
          <CardContent>
            <Box display="flex" alignItems="center">
              {(adminStats?.general_stats?.total_pnl || 0) >= 0 ? 
                <TrendingUp color="success" sx={{ mr: 2 }} /> :
                <TrendingDown color="error" sx={{ mr: 2 }} />
              }
              <Box>
                <Typography variant="h6" component="div">
                  {formatCurrency(adminStats?.general_stats?.total_pnl)}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  PnL Total
                </Typography>
              </Box>
            </Box>
          </CardContent>
        </Card>
      </Grid>
    </Grid>
  );

  // Renderizar lista de usuários
  const renderUsersTable = () => (
    <Card>
      <CardContent>
        <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
          <Typography variant="h6">Usuários Cadastrados</Typography>
          <Box display="flex" gap={2}>
            <TextField
              size="small"
              placeholder="Buscar usuários..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              InputProps={{
                startAdornment: <Search />
              }}
            />
            <FormControl size="small" sx={{ minWidth: 120 }}>
              <InputLabel>Status</InputLabel>
              <Select
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
                label="Status"
              >
                <MenuItem value="all">Todos</MenuItem>
                <MenuItem value="active">Ativos</MenuItem>
                <MenuItem value="inactive">Inativos</MenuItem>
              </Select>
            </FormControl>
            <Button
              variant="outlined"
              startIcon={<Refresh />}
              onClick={loadUsers}
            >
              Atualizar
            </Button>
          </Box>
        </Box>

        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Nome</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Trades</TableCell>
                <TableCell>PnL Total</TableCell>
                <TableCell>Último Trade</TableCell>
                <TableCell>Ações</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {filteredUsers.map((user) => (
                <TableRow key={user.id}>
                  <TableCell>
                    <Box display="flex" alignItems="center">
                      {user.is_admin && (
                        <SupervisorAccount color="warning" sx={{ mr: 1 }} />
                      )}
                      {user.full_name}
                    </Box>
                  </TableCell>
                  <TableCell>{user.email}</TableCell>
                  <TableCell>
                    <Chip
                      label={user.is_active ? 'Ativo' : 'Inativo'}
                      color={user.is_active ? 'success' : 'error'}
                      size="small"
                    />
                  </TableCell>
                  <TableCell>
                    <Badge badgeContent={user.stats.open_trades} color="primary">
                      {user.stats.total_trades}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    <Typography
                      color={user.stats.total_pnl >= 0 ? 'success.main' : 'error.main'}
                    >
                      {formatCurrency(user.stats.total_pnl)}
                    </Typography>
                  </TableCell>
                  <TableCell>{user.stats.last_trade_date}</TableCell>
                  <TableCell>
                    <Tooltip title="Ver detalhes">
                      <IconButton
                        onClick={() => loadUserDetails(user.id)}
                        size="small"
                      >
                        <Visibility />
                      </IconButton>
                    </Tooltip>
                    <Tooltip title={user.is_active ? 'Desativar' : 'Ativar'}>
                      <IconButton
                        onClick={() => toggleUserStatus(user.id)}
                        size="small"
                        color={user.is_active ? 'error' : 'success'}
                      >
                        {user.is_active ? <Block /> : <CheckCircle />}
                      </IconButton>
                    </Tooltip>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      </CardContent>
    </Card>
  );

  // Renderizar trades por símbolo
  const renderSymbolTrades = () => (
    <Card>
      <CardContent>
        <Typography variant="h6" gutterBottom>
          Operações por Símbolo
        </Typography>
        <Grid container spacing={2}>
          {symbolTrades.map((symbol) => (
            <Grid item xs={12} md={6} lg={4} key={symbol.symbol}>
              <Card variant="outlined">
                <CardContent>
                  <Typography variant="h6" gutterBottom>
                    {symbol.symbol}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" gutterBottom>
                    {symbol.total_trades} trades total
                  </Typography>
                  
                  <Box mt={2}>
                    <Typography variant="subtitle2" gutterBottom>
                      Usuários operando:
                    </Typography>
                    {symbol.users.map((user) => (
                      <Chip
                        key={user.user_id}
                        label={`${user.user_id}: ${user.trades_count} trades`}
                        size="small"
                        sx={{ mr: 1, mb: 1 }}
                        onClick={() => loadUserDetails(user.user_id)}
                      />
                    ))}
                  </Box>
                  
                  <Button
                    variant="contained"
                    color="error"
                    size="small"
                    fullWidth
                    sx={{ mt: 2 }}
                    onClick={() => closeAllSymbolPositions(symbol.symbol)}
                  >
                    Fechar Todas Posições
                  </Button>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>
      </CardContent>
    </Card>
  );

  // Renderizar posições abertas
  const renderOpenPositions = () => (
    <Card>
      <CardContent>
        <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
          <Typography variant="h6">Posições Abertas</Typography>
          <Button
            variant="contained"
            color="error"
            disabled={selectedPositions.length === 0}
            onClick={() => setClosePositionDialog(true)}
          >
            Fechar Selecionadas ({selectedPositions.length})
          </Button>
        </Box>

        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell padding="checkbox">
                  <FormControlLabel
                    control={
                      <Switch
                        checked={selectedPositions.length === openPositions.length}
                        onChange={(e) => {
                          if (e.target.checked) {
                            setSelectedPositions(openPositions.map(p => p.trade_id));
                          } else {
                            setSelectedPositions([]);
                          }
                        }}
                      />
                    }
                    label="Todos"
                  />
                </TableCell>
                <TableCell>Usuário</TableCell>
                <TableCell>Símbolo</TableCell>
                <TableCell>Lado</TableCell>
                <TableCell>Tamanho</TableCell>
                <TableCell>Preço Entrada</TableCell>
                <TableCell>PnL Atual</TableCell>
                <TableCell>Aberto em</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {openPositions.map((position) => (
                <TableRow key={position.trade_id}>
                  <TableCell padding="checkbox">
                    <Switch
                      checked={selectedPositions.includes(position.trade_id)}
                      onChange={(e) => {
                        if (e.target.checked) {
                          setSelectedPositions([...selectedPositions, position.trade_id]);
                        } else {
                          setSelectedPositions(selectedPositions.filter(id => id !== position.trade_id));
                        }
                      }}
                    />
                  </TableCell>
                  <TableCell>
                    <Tooltip title={position.user_email}>
                      <span>{position.user_name}</span>
                    </Tooltip>
                  </TableCell>
                  <TableCell>{position.symbol}</TableCell>
                  <TableCell>
                    <Chip
                      label={position.side}
                      color={position.side === 'long' ? 'success' : 'error'}
                      size="small"
                    />
                  </TableCell>
                  <TableCell>{position.size}</TableCell>
                  <TableCell>{formatCurrency(position.entry_price)}</TableCell>
                  <TableCell>
                    <Typography
                      color={position.current_pnl >= 0 ? 'success.main' : 'error.main'}
                    >
                      {formatCurrency(position.current_pnl)}
                    </Typography>
                  </TableCell>
                  <TableCell>{formatDate(position.opened_at)}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      </CardContent>
    </Card>
  );

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h4" gutterBottom>
        <SupervisorAccount sx={{ mr: 2, verticalAlign: 'middle' }} />
        Painel Administrativo
      </Typography>

      {adminStats && renderStatsPanel()}

      <Tabs
        value={currentTab}
        onChange={(e, newValue) => setCurrentTab(newValue)}
        sx={{ mb: 3 }}
      >
        <Tab label="Usuários" />
        <Tab label="Trades por Símbolo" />
        <Tab label="Posições Abertas" />
      </Tabs>

      {currentTab === 0 && renderUsersTable()}
      {currentTab === 1 && renderSymbolTrades()}
      {currentTab === 2 && renderOpenPositions()}

      {/* Dialog de detalhes do usuário */}
      <Dialog
        open={userDetailsOpen}
        onClose={() => setUserDetailsOpen(false)}
        maxWidth="lg"
        fullWidth
      >
        <DialogTitle>
          Detalhes do Usuário
          <IconButton
            onClick={() => setUserDetailsOpen(false)}
            sx={{ position: 'absolute', right: 8, top: 8 }}
          >
            <Close />
          </IconButton>
        </DialogTitle>
        <DialogContent>
          {selectedUser && (
            <Box>
              <Grid container spacing={2} mb={3}>
                <Grid item xs={12} md={6}>
                  <Typography variant="h6">{selectedUser.user.full_name}</Typography>
                  <Typography variant="body2" color="text.secondary">
                    {selectedUser.user.email}
                  </Typography>
                </Grid>
                <Grid item xs={12} md={6}>
                  <Box display="flex" gap={1}>
                    <Chip
                      label={selectedUser.user.is_active ? 'Ativo' : 'Inativo'}
                      color={selectedUser.user.is_active ? 'success' : 'error'}
                    />
                    {selectedUser.user.is_admin && (
                      <Chip label="Admin" color="warning" />
                    )}
                  </Box>
                </Grid>
              </Grid>

              <Typography variant="h6" gutterBottom>
                Estatísticas
              </Typography>
              <Grid container spacing={2} mb={3}>
                <Grid item xs={3}>
                  <Typography variant="body2">Total Trades</Typography>
                  <Typography variant="h6">{selectedUser.stats.total_trades}</Typography>
                </Grid>
                <Grid item xs={3}>
                  <Typography variant="body2">Abertas</Typography>
                  <Typography variant="h6">{selectedUser.stats.open_trades}</Typography>
                </Grid>
                <Grid item xs={3}>
                  <Typography variant="body2">Taxa Vitória</Typography>
                  <Typography variant="h6">{selectedUser.stats.win_rate}%</Typography>
                </Grid>
                <Grid item xs={3}>
                  <Typography variant="body2">PnL Total</Typography>
                  <Typography
                    variant="h6"
                    color={selectedUser.stats.total_pnl >= 0 ? 'success.main' : 'error.main'}
                  >
                    {formatCurrency(selectedUser.stats.total_pnl)}
                  </Typography>
                </Grid>
              </Grid>

              <Typography variant="h6" gutterBottom>
                Histórico de Trades
              </Typography>
              <TableContainer>
                <Table size="small">
                  <TableHead>
                    <TableRow>
                      <TableCell>Símbolo</TableCell>
                      <TableCell>Lado</TableCell>
                      <TableCell>Status</TableCell>
                      <TableCell>PnL</TableCell>
                      <TableCell>Data</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {selectedUser.trades.slice(0, 10).map((trade) => (
                      <TableRow key={trade.id}>
                        <TableCell>{trade.symbol}</TableCell>
                        <TableCell>
                          <Chip
                            label={trade.side}
                            color={trade.side === 'long' ? 'success' : 'error'}
                            size="small"
                          />
                        </TableCell>
                        <TableCell>
                          <Chip
                            label={trade.status}
                            color={trade.status === 'open' ? 'info' : 'default'}
                            size="small"
                          />
                        </TableCell>
                        <TableCell>
                          <Typography
                            color={trade.pnl >= 0 ? 'success.main' : 'error.main'}
                          >
                            {formatCurrency(trade.pnl)}
                          </Typography>
                        </TableCell>
                        <TableCell>{formatDate(trade.opened_at)}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>
            </Box>
          )}
        </DialogContent>
      </Dialog>

      {/* Dialog de confirmação para fechar posições */}
      <Dialog
        open={closePositionDialog}
        onClose={() => setClosePositionDialog(false)}
      >
        <DialogTitle>Confirmar Fechamento de Posições</DialogTitle>
        <DialogContent>
          <Alert severity="warning" sx={{ mb: 2 }}>
            Você está prestes a fechar {selectedPositions.length} posição(ões) aberta(s).
            Esta ação não pode ser desfeita.
          </Alert>
          <Typography>
            Deseja realmente continuar?
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setClosePositionDialog(false)}>
            Cancelar
          </Button>
          <Button
            onClick={closeSelectedPositions}
            color="error"
            variant="contained"
          >
            Confirmar Fechamento
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default AdminDashboard;
